:root {
  --bg-card: #ffffff;
  --bg-dashboard: #f0f7f0;
  --border-main: #c8e0c8;
  --accent-green: #3a8a4a;
  --accent-green-light: #e6f4e8;
  --text-primary: #1a2e1a;
  --text-secondary: #5a7a5a;
  --text-muted: #8aaa8a;
  --status-ok: #2e8b57;
  --status-ok-bg: #e6f4ec;
  --status-warn: #c87800;
  --status-warn-bg: #fff4e0;
  --status-urgent: #c0392b;
  --status-urgent-bg: #fdecea;
  --strip-bg: #2d6a3f;
  --strip-text: #ffffff;
  --strip-muted: #a8d4b4;
  --divider-strip: #3d8a52;
}

.dashboard {
  width: 500px;
  background-color: var(--bg-dashboard);
  border: 2px solid var(--border-main);
  border-radius: 16px;
  overflow: hidden;
  margin: 0 auto;
}

.dash-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 20px;
  background-color: var(--bg-card);
  border-bottom: 2px solid var(--border-main);
}

.dash-title {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-primary);
}

.dash-count {
  font-size: 13px;
  font-weight: 600;
  color: var(--accent-green);
  background-color: var(--accent-green-light);
  padding: 4px 10px;
  border-radius: 20px;
}

.plant-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  padding: 12px;
}

.plant-card {
  background-color: var(--bg-card);
  border: 1.5px solid var(--border-main);
  border-radius: 12px;
  padding: 12px;
  display: flex;
  align-items: center;
  gap: 10px;
}

.plant-icon {
  font-size: 28px;
  line-height: 1;
  flex-shrink: 0;
}

.plant-info {
  display: flex;
  flex-direction: column;
  flex: 1;
  gap: 2px;
}

.plant-name {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-primary);
}

.plant-type {
  font-size: 11px;
  color: var(--text-muted);
  font-weight: 500;
}

.water-status {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 4px 8px;
  border-radius: 8px;
  flex-shrink: 0;
}

.water-status.ok {
  background-color: var(--status-ok-bg);
}

.water-status.warn {
  background-color: var(--status-warn-bg);
}

.water-status.urgent {
  background-color: var(--status-urgent-bg);
}

.status-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  flex-shrink: 0;
}

.water-status.ok .status-dot {
  background-color: var(--status-ok);
}

.water-status.warn .status-dot {
  background-color: var(--status-warn);
}

.water-status.urgent .status-dot {
  background-color: var(--status-urgent);
}

.status-label {
  font-size: 11px;
  font-weight: 600;
  white-space: nowrap;
}

.water-status.ok .status-label {
  color: var(--status-ok);
}

.water-status.warn .status-label {
  color: var(--status-warn);
}

.water-status.urgent .status-label {
  color: var(--status-urgent);
}

.care-strip {
  display: flex;
  align-items: center;
  background-color: var(--strip-bg);
  padding: 14px 20px;
}

.care-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  gap: 3px;
}

.care-value {
  font-size: 18px;
  font-weight: 700;
  color: var(--strip-text);
  line-height: 1;
}

.care-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--strip-muted);
}

.care-divider {
  width: 1px;
  height: 32px;
  background-color: var(--divider-strip);
}
